import React from "react";

function PiggyBank({ totalSavings }) {

  return (
    <div className="card piggy">

      <h3>Virtual Piggy Bank 🐷</h3>

      <div style={{
        fontSize: "40px",
        margin: "10px"
      }}>
        🐷
      </div>

      <h2>₹{Number(totalSavings).toFixed(2)}</h2>

      <p>Your round-up savings are growing!</p>

    </div>
  );

}

export default PiggyBank;
